class Solution {
    public String gcdOfStrings(String str1, String str2) {
        String gcd = str1.length() < str2.length() ? str1 : str2;
        while (true) {
            if (str1.length() % gcd.length() == 0 && str2.length() % gcd.length() == 0 && str1.equals(str1.substring(0, gcd.length()).repeat(str1.length() / gcd.length())) && str2.equals(str2.substring(0, gcd.length()).repeat(str2.length() / gcd.length()))) {
                return gcd;
            }
            gcd = gcd.substring(0, gcd.length() - 1);
        }
    }
}
